import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Modality, Location, FilmSize, ContrastType, DailyActivityLog, DailyContrastLog, WeeklyOperationsLog, AppState } from '../types';

interface AppContextType extends AppState {
    addModality: (modality: Modality) => void;
    removeModality: (id: string) => void;
    addActivityLog: (log: DailyActivityLog) => void;
    addContrastLog: (log: DailyContrastLog) => void;
    addWeeklyOpsLog: (log: WeeklyOperationsLog) => void;
}

const defaultState: AppState = {
    modalities: [
        { id: '1', name: 'MRI' },
        { id: '2', name: 'CT SCAN' },
        { id: '3', name: 'X-RAY' },
        { id: '4', name: 'FLUORO' },
        { id: '5', name: 'MAMMO' },
        { id: '6', name: 'ULTRASOUND' },
        { id: '7', name: 'DOPPLER' },
    ],
    locations: [
        { id: '1', name: 'Upstairs' },
        { id: '2', name: 'Downstairs BT' },
        { id: '3', name: 'Ayinke' },
    ],
    filmSizes: [
        { id: '1', name: '10x12' },
        { id: '2', name: '14x17' },
    ],
    contrastTypes: [
        { id: '1', name: 'Scanlux 300mg' },
        { id: '2', name: 'Scanlux 370mg' },
        { id: '3', name: 'Gastrolux' },
        { id: '4', name: 'Urografin' },
        { id: '5', name: 'Cyclolux (MRI)' },
    ],
    activityLogs: [],
    contrastLogs: [],
    weeklyOpsLogs: [],
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [state, setState] = useState<AppState>(() => {
        const saved = localStorage.getItem('radiologyData');
        if (saved) {
            try {
                return JSON.parse(saved);
            } catch (e) {
                console.error('Failed to load data from localStorage', e);
                return defaultState;
            }
        }
        return defaultState;
    });

    useEffect(() => {
        localStorage.setItem('radiologyData', JSON.stringify(state));
    }, [state]);

    const addModality = (modality: Modality) => {
        setState(prev => ({ ...prev, modalities: [...prev.modalities, modality] }));
    };

    const removeModality = (id: string) => {
        setState(prev => ({ ...prev, modalities: prev.modalities.filter(m => m.id !== id) }));
    };

    const addActivityLog = (log: DailyActivityLog) => {
        setState(prev => ({ ...prev, activityLogs: [...prev.activityLogs, log] }));
    };

    const addContrastLog = (log: DailyContrastLog) => {
        setState(prev => ({ ...prev, contrastLogs: [...prev.contrastLogs, log] }));
    };

    const addWeeklyOpsLog = (log: WeeklyOperationsLog) => {
        setState(prev => ({ ...prev, weeklyOpsLogs: [...prev.weeklyOpsLogs, log] }));
    };

    return (
        <AppContext.Provider value={{
            ...state,
            addModality,
            removeModality,
            addActivityLog,
            addContrastLog,
            addWeeklyOpsLog,
        }}>
            {children}
        </AppContext.Provider>
    );
};

export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) {
        throw new Error('useAppContext must be used within an AppProvider');
    }
    return context;
};

import React from 'react';
import { useAppContext } from '../context/AppContext';
import { Activity, Droplet, CreditCard } from 'lucide-react';
import { calculateTotalInvestigations, calculateTotalContrastML, calculateTotalRevenue } from '../utils/calculations';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

export const Dashboard: React.FC = () => {
    const { activityLogs, contrastLogs, modalities } = useAppContext();

    const totalInvestigations = calculateTotalInvestigations(activityLogs);
    const totalContrastML = calculateTotalContrastML(contrastLogs);
    const totalRevenue = calculateTotalRevenue(activityLogs);

    // Group activity by modality for chart
    const modalityData = modalities.map(modality => {
        const logsForModality = activityLogs.filter(log => log.modalityId === modality.id);
        const count = calculateTotalInvestigations(logsForModality);
        return {
            name: modality.name,
            investigations: count
        };
    }).filter(data => data.investigations > 0);

    const colors = ['#3b82f6', '#8b5cf6', '#ec4899', '#10b981', '#f59e0b', '#ef4444', '#06b6d4'];

    const StatCard = ({ title, value, icon: Icon, colorClass }: any) => (
        <div className="bg-surface rounded-xl border border-surface-hover p-6 shadow-sm hover:-translate-y-1 transition-transform duration-300">
            <div className="flex justify-between items-start">
                <div>
                    <p className="text-text-secondary text-sm font-medium mb-1">{title}</p>
                    <h3 className="text-3xl font-bold tracking-tight text-white">{value}</h3>
                </div>
                <div className={`p-3 rounded-xl ${colorClass}`}>
                    <Icon className="w-6 h-6 text-white" />
                </div>
            </div>
        </div>
    );

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div>
                <h2 className="text-3xl font-bold tracking-tight">Dashboard Overview</h2>
                <p className="text-text-secondary mt-1">High-level metrics and performance analytics.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <StatCard
                    title="Total Investigations"
                    value={totalInvestigations}
                    icon={Activity}
                    colorClass="bg-primary-500 shadow-primary-500/20 shadow-lg"
                />
                <StatCard
                    title="Total Revenue (₦)"
                    value={totalRevenue.toLocaleString()}
                    icon={CreditCard}
                    colorClass="bg-green-500 shadow-green-500/20 shadow-lg"
                />
                <StatCard
                    title="Contrast Used (ML)"
                    value={totalContrastML}
                    icon={Droplet}
                    colorClass="bg-purple-500 shadow-purple-500/20 shadow-lg"
                />
            </div>

            <div className="bg-surface rounded-xl border border-surface-hover p-6 shadow-sm">
                <h3 className="text-lg font-semibold mb-6">Investigations by Modality</h3>
                {modalityData.length === 0 ? (
                    <div className="py-12 text-center text-text-secondary">
                        <BarChart className="w-12 h-12 text-surface-hover mx-auto mb-3" />
                        <p>No activity data available to generate charts.</p>
                        <p className="text-sm text-surface-hover mt-1">Add logs in Daily Logging to see visual analytics.</p>
                    </div>
                ) : (
                    <div className="h-80 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={modalityData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                                <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                                <XAxis dataKey="name" stroke="#94a3b8" tick={{ fill: '#94a3b8' }} axisLine={false} tickLine={false} />
                                <YAxis stroke="#94a3b8" tick={{ fill: '#94a3b8' }} axisLine={false} tickLine={false} />
                                <Tooltip
                                    cursor={{ fill: '#334155', opacity: 0.4 }}
                                    contentStyle={{ backgroundColor: '#1e293b', border: '1px solid #334155', borderRadius: '8px', color: '#fff' }}
                                    itemStyle={{ color: '#3b82f6', fontWeight: 600 }}
                                />
                                <Bar dataKey="investigations" radius={[6, 6, 0, 0]}>
                                    {modalityData.map((_entry, index) => (
                                        <Cell key={`cell-${index}`} fill={colors[index % colors.length]} />
                                    ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                )}
            </div>
        </div>
    );
};
